def predict(triples: list[Triple]) -> str:
    """Generate a readable sentence from a list of triples."""
    if not triples:
        return ""

    # Build a lookup for all subjects to identify hierarchical relationships
    subject_to_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_to_triples:
            subject_to_triples[t.subject] = []
        subject_to_triples[t.subject].append(t)

    # Identify the main subject (typically an airport - first subject or one with airport in name)
    main_subject = triples[0].subject
    for t in triples:
        if "Airport" in t.subject or "airport" in t.subject.lower():
            main_subject = t.subject
            break

    # Collect all triples for the main subject
    main_triples = subject_to_triples.get(main_subject, [])

    # Build phrases for main subject
