        phrase = _get_phrase(p, o, is_main_subject=True)
        if phrase:
            main_phrases.append(phrase)

    # Collect related information about objects that are also subjects
    related_info: list[str] = []
    for t in main_triples:
        obj = t.object
        if obj in subject_to_triples and obj != main_subject:
            obj_triples = subject_to_triples[obj]
            for ot in obj_triples:
                if ot.predicate not in ["cityServed", "location", "country", "isPartOf"]:
                    # Skip if this is already captured in main subject
                    phrase = _get_phrase(ot.predicate, ot.object, is_main_subject=False, entity=obj)
                    if phrase:
                        related_info.append(phrase)

    # Build a single complex sentence
    if not main_phrases:
        # Fallback to original approach
        return _build_simple_sentence(triples)

    # Combine main phrases with relative clauses for related info
    if len(main_phrases) == 1:
        base = main_phrases[0]
    else:
        base = main_phrases[0] + ", " + ", ".join(main_phrases[1:])

    # Add related information with relative clauses
    if related_info:
        if len(related_info) == 1:
            base += f", which {related_info[0]}"
        else:
            base += f", which {', '.join(related_info[:-1])} and {related_info[-1]}"

    # Ensure proper capitalization and punctuation
    sentence = base[0].upper() + base[1:]
    if not sentence.endswith('.'):
        sentence += '.'
    return sentence

